import javax.jws.WebMethod;
import javax.jws.WebService;
import javax.xml.ws.Endpoint;
import java.util.HashMap;
import java.util.Map;

@WebService
public class EmployeeManagementService {

    private Map<String, Employee> employeeDatabase = new HashMap<>();

    @WebMethod
    public String updateSalary(String employeeId, double newSalary) {
        if (!isValidEmployeeId(employeeId) || newSalary < 0) {
            return "Invalid input";
        }
        Employee employee = employeeDatabase.get(employeeId);
        if (employee != null) {
            employee.setSalary(newSalary);
            return "Salary updated successfully";
        }
        return "Employee not found";
    }

    @WebMethod
    public String addPerformanceReview(String employeeId, String review) {
        if (!isValidEmployeeId(employeeId) || review == null || review.isEmpty()) {
            return "Invalid input";
        }
        Employee employee = employeeDatabase.get(employeeId);
        if (employee != null) {
            employee.addReview(review);
            return "Performance review added successfully";
        }
        return "Employee not found";
    }

    @WebMethod
    public String terminateEmployee(String employeeId) {
        if (!isValidEmployeeId(employeeId)) {
            return "Invalid input";
        }
        if (employeeDatabase.remove(employeeId) != null) {
            return "Employee terminated successfully";
        }
        return "Employee not found";
    }

    private boolean isValidEmployeeId(String employeeId) {
        return employeeId != null && employeeId.matches("EMP\\d{3}");
    }

    public static void main(String[] args) {
        Endpoint.publish("http://localhost:8080/EmployeeManagementService", new EmployeeManagementService());
    }
}

class Employee {
    private String id;
    private double salary;
    private String performanceReviews;

    public Employee(String id, double salary) {
        this.id = id;
        this.salary = salary;
        this.performanceReviews = "";
    }

    public void setSalary(double salary) {
        this.salary = salary;
    }

    public void addReview(String review) {
        this.performanceReviews += review + "\n";
    }
}